+"use client";
+
+import { useMutation } from "@tanstack/react-query";
+import { ai } from "@/lib/api/fisga";
+import { track } from "@/lib/analytics";
+import type { FitScoreInput, GenerateApproachInput } from "@/lib/api/types";
+
+export function useGenerateApproach() {
+  return useMutation({
+    mutationFn: (input: GenerateApproachInput) => ai.generateApproach(input),
+    onSuccess: (_data, vars) => {
+      track({
+        name: "ai_approach_generated",
+        props: { channel: vars.channel, tier: vars.tier ?? "default" },
+      });
+    },
+  });
+}
+
+export function useFitScore() {
+  return useMutation({
+    mutationFn: (input: FitScoreInput) => ai.fitScore(input),
+    onSuccess: () => track({ name: "fit_score_generated" }),
+  });
+}


