+"use client";
+
+import { useMutation, useQuery, useQueryClient } from "@tanstack/react-query";
+import { billing } from "@/lib/api/fisga";
+import { track } from "@/lib/analytics";
+import type { Meter, PlanCode } from "@/lib/api/types";
+
+export function usePlans() {
+  return useQuery({ queryKey: ["billing", "plans"], queryFn: billing.plans, staleTime: 300_000 });
+}
+
+export function useCreditBalance() {
+  return useQuery({ queryKey: ["billing", "balance"], queryFn: billing.balance });
+}
+
+export function useSubscription() {
+  return useQuery({ queryKey: ["billing", "subscription"], queryFn: billing.subscription });
+}
+
+export function useBuyCredits() {
+  const qc = useQueryClient();
+  return useMutation({
+    mutationFn: ({ meter, quantity }: { meter: Meter; quantity: number }) =>
+      billing.buyCredits(meter, quantity),
+    onSuccess: (result) => {
+      track({
+        name: "credits_purchased",
+        props: { meter: result.meter, quantity: result.quantity },
+      });
+      void qc.invalidateQueries({ queryKey: ["billing"] });
+    },
+  });
+}
+
+export function useChangePlan() {
+  const qc = useQueryClient();
+  return useMutation({
+    mutationFn: (planCode: PlanCode) => billing.changePlan(planCode),
+    onSuccess: () => void qc.invalidateQueries({ queryKey: ["billing"] }),
+  });
+}


