+"use client";
+
+import { keepPreviousData, useQuery } from "@tanstack/react-query";
+import { companies } from "@/lib/api/fisga";
+import { track } from "@/lib/analytics";
+import type { CompanySearchFilters } from "@/lib/api/types";
+
+/** Busca na base CNPJ — ilimitada e grátis (nunca debita). */
+export function useCompanySearch(filters: CompanySearchFilters, enabled = true) {
+  return useQuery({
+    queryKey: ["companies", "search", filters],
+    queryFn: async () => {
+      const result = await companies.search(filters);
+      track({
+        name: "search_performed",
+        props: {
+          filters: Object.entries(filters)
+            .filter(([k, v]) => v !== undefined && k !== "page" && k !== "pageSize")
+            .map(([k]) => k),
+          results: result.items.length,
+        },
+      });
+      return result;
+    },
+    enabled,
+    placeholderData: keepPreviousData,
+  });
+}


