+"use client";
+
+import { useMutation, useQuery, useQueryClient } from "@tanstack/react-query";
+import { enrichment } from "@/lib/api/fisga";
+import { track } from "@/lib/analytics";
+import { leadKeys } from "./use-leads";
+
+/**
+ * Enriquecimento é assíncrono (fila BullMQ): request → poll até done/failed.
+ * O poll usa GET /enrichment/:id (endpoint estendido do backend).
+ */
+
+export function useRequestEnrichment() {
+  const qc = useQueryClient();
+  return useMutation({
+    mutationFn: (companyCnpj: string) => enrichment.request(companyCnpj),
+    onSuccess: () => {
+      track({ name: "enrichment_requested" });
+      void qc.invalidateQueries({ queryKey: ["billing"] });
+    },
+  });
+}
+
+export function useEnrichmentStatus(jobId: string | null) {
+  const qc = useQueryClient();
+  return useQuery({
+    queryKey: ["enrichment", jobId],
+    queryFn: async () => {
+      const job = await enrichment.status(jobId!);
+      if (job.status === "done" || job.status === "failed") {
+        track({
+          name: "enrichment_completed",
+          props: { status: job.status === "done" ? "done" : "failed" },
+        });
+        void qc.invalidateQueries({ queryKey: leadKeys.all });
