"use client";

import { useMutation, useQueryClient } from "@tanstack/react-query";
import { integrations } from "@/lib/api/fisga";
import { track } from "@/lib/analytics";
import { leadKeys } from "./use-leads";

export function useImportCsv() {
  const qc = useQueryClient();
  return useMutation({
    mutationFn: (file: File) => integrations.importCsv(file),
    onSuccess: (summary) => {
      track({ name: "csv_imported", props: { imported: summary.imported } });
      void qc.invalidateQueries({ queryKey: leadKeys.all });
    },
  });
}

export function useImportSheet() {
  const qc = useQueryClient();
  return useMutation({
    mutationFn: (sheetUrl: string) => integrations.importSheet(sheetUrl),
    onSuccess: (summary) => {
      track({ name: "sheet_imported", props: { imported: summary.imported } });
      void qc.invalidateQueries({ queryKey: leadKeys.all });
    },
  });
}

export function useExportLeads() {
  return useMutation({
    mutationFn: async () => {
      const blob = await integrations.exportLeadsCsv();
      const url = URL.createObjectURL(blob);
      const a = document.createElement("a");
      a.href = url;
      a.download = "leads.csv";
      a.click();
      URL.revokeObjectURL(url);
    },
    onSuccess: () => track({ name: "leads_exported" }),
  });
}

