"use client";

import { bff } from "./client";
import type {
  ActivationData,
  Activity,
  ChannelAccount,
  CompanySearchFilters,
  ConsentStatus,
  ContentAsset,
  CreditBalance,
  DashboardData,
  Disclosure,
  EnrichmentJobStatus,
  EnrichmentRequestResult,
  EstablishmentSearchResult,
  FitScoreInput,
  GenerateApproachInput,
  ImportSummary,
  Lead,
  LeadDetail,
  LeadStage,
  Meter,
  Paginated,
  Plan,
  PlanCode,
  QualityTier,
  RiskChannelType,
  Subscription,
  WhatsappLink,
  Workspace,
  ActivityType,
} from "./types";

/**
 * SDK de domínio Fisga (client → BFF → Nest).
 * Normaliza os 3 formatos de paginação do backend em `Paginated<T>`.
 */

// ---- workspaces ----

export const workspaces = {
  list: () => bff<Workspace[]>("/workspaces"),
};

// ---- leads ----

export const leads = {
  list: (params: { stage?: LeadStage; page?: number; pageSize?: number } = {}) =>
    bff<{ data: Lead[]; meta: { page: number; pageSize: number; total: number } }>(
      "/leads",
      { query: params },
    ).then(
      (r): Paginated<Lead> => ({
        items: r.data,
        page: r.meta.page,
        pageSize: r.meta.pageSize,
        total: r.meta.total,
        hasMore: r.meta.page * r.meta.pageSize < r.meta.total,
      }),
    ),

  today: () => bff<Lead[]>("/leads/today"),

  detail: (id: string) => bff<LeadDetail>(`/leads/${id}`),

  /** revelar: cria lead a partir da busca (debita 1 crédito de reveal) */
  reveal: (companyCnpj: string) =>
    bff<{ lead: Lead; alreadyInPipeline: boolean }>("/leads", {
      method: "POST",
      body: { companyCnpj },
    }),

  moveStage: (id: string, stage: LeadStage) =>
    bff<Lead>(`/leads/${id}/stage`, { method: "PATCH", body: { stage } }),

  addActivity: (
    id: string,
    activity: { type: ActivityType; note?: string; nextActivityAt?: string },
  ) =>
    bff<{ activity: Activity; lead: Lead }>(`/leads/${id}/activities`, {
      method: "POST",
      body: activity,
    }),

  assignOwner: (id: string, ownerUserId: string) =>
    bff<Lead>(`/leads/${id}/owner`, { method: "PATCH", body: { ownerUserId } }),

  whatsappLink: (id: string, message?: string) =>
    bff<WhatsappLink>(`/leads/${id}/whatsapp`, {
      method: "POST",
      body: message ? { message } : {},
    }),
};

// ---- companies (busca — ilimitada e grátis) ----

export const companies = {
  search: (filters: CompanySearchFilters) => {
    const { cnaes, includeInactive, ...rest } = filters;
    return bff<{
      data: EstablishmentSearchResult[];
      meta: { page: number; pageSize: number; hasMore: boolean };
    }>("/companies/search", {
      query: {
        ...rest,
        cnaes: cnaes?.length ? cnaes.join(",") : undefined,
        includeInactive: includeInactive ? "true" : undefined,
      },
    }).then(
      (r): Paginated<EstablishmentSearchResult> => ({
        items: r.data,
        page: r.meta.page,
        pageSize: r.meta.pageSize,
        total: null,
        hasMore: r.meta.hasMore,
      }),
    );
  },
};

// ---- enrichment (async: request → poll) ----

export const enrichment = {
  request: (companyCnpj: string) =>
    bff<EnrichmentRequestResult>("/enrichment", {
      method: "POST",
      body: { companyCnpj },
    }),
  status: (jobId: string) => bff<EnrichmentJobStatus>(`/enrichment/${jobId}`),
};

// ---- IA da Fisga ----

export const ai = {
  generateApproach: (input: GenerateApproachInput) =>
    bff<{ message: string }>("/ai/approach", { method: "POST", body: input }),
  fitScore: (input: FitScoreInput) =>
    bff<{ score: number }>("/ai/fit-score", { method: "POST", body: input }),
};

// ---- dashboard / activation ----

export const dashboard = {
  get: () => bff<DashboardData>("/dashboard"),
};

export const activation = {
  get: () => bff<ActivationData>("/activation"),
};

// ---- consent / canais ----

export const consent = {
  disclosures: () => bff<Disclosure[]>("/consent/disclosures"),
  status: () => bff<ConsentStatus[]>("/consent/status"),
  accept: (type: RiskChannelType, textVersion: string) =>
    bff<unknown>("/consent", { method: "POST", body: { type, textVersion } }),
};

export const channels = {
  list: () => bff<ChannelAccount[]>("/channels"),
  connect: (type: RiskChannelType, identifier: string) =>
    bff<ChannelAccount & { qrPayload?: string }>(`/channels/${type}/connect`, {
      method: "POST",
      body: { identifier },
    }),
  disconnect: (type: RiskChannelType) =>
    bff<void>(`/channels/${type}`, { method: "DELETE" }),
};

// ---- estúdio ----

export const studio = {
  create: (input: { prompt: string; tier?: QualityTier; width?: number; height?: number }) =>
    bff<ContentAsset>("/content-studio/images", { method: "POST", body: input }),
  list: (params: { page?: number; pageSize?: number } = {}) =>
    bff<{ items: ContentAsset[]; total: number; page: number; pageSize: number }>(
      "/content-studio/images",
      { query: params },
    ).then(
      (r): Paginated<ContentAsset> => ({
        items: r.items,
        page: r.page,
        pageSize: r.pageSize,
        total: r.total,
        hasMore: r.page * r.pageSize < r.total,
      }),
    ),
  get: (id: string) => bff<ContentAsset>(`/content-studio/images/${id}`),
};

// ---- integrações ----

export const integrations = {
  importCsv: (file: File) => {
    const form = new FormData();
    form.append("file", file);
    return bff<ImportSummary>("/integrations/import/csv", {
      method: "POST",
      rawBody: form,
    });
  },
  importSheet: (sheetUrl: string) =>
    bff<ImportSummary>("/integrations/import/sheet", {
      method: "POST",
      body: { sheetUrl },
    }),
  /** devolve Blob (CSV) — LGPD: backend suprime PII com opt-out */
  exportLeadsCsv: () => bff<Blob>("/integrations/export/leads.csv"),
};

// ---- billing ----

export const billing = {
  plans: () => bff<Plan[]>("/billing/plans"),
  balance: () => bff<CreditBalance[]>("/billing/balance"),
  subscription: () => bff<Subscription | null>("/billing/subscription"),
  buyCredits: (meter: Meter, quantity: number) =>
    bff<{ meter: Meter; quantity: number; priceCents: number; balance: number }>(
      "/billing/credits",
      { method: "POST", body: { meter, quantity } },
    ),
  changePlan: (planCode: PlanCode) =>
    bff<Subscription>("/billing/subscription", {
      method: "PATCH",
      body: { planCode },
    }),
};

