"use client";

import posthog from "posthog-js";
import { useConsent } from "@/store/consent";
import { publicEnv } from "@/lib/env";

/**
 * Tracking plan unificado — TODO evento passa por track().
 * GA4 + PostHog só disparam com consentimento LGPD concedido.
 */

export type AnalyticsEvent =
  | { name: "sign_up"; props?: { method: "email" } }
  | { name: "login" }
  | { name: "logout" }
  | { name: "cta_click"; props: { cta: string; location: string } }
  | { name: "pricing_view" }
  | { name: "faq_open"; props: { question: string } }
  | { name: "search_performed"; props: { filters: string[]; results: number } }
  | { name: "lead_revealed"; props: { cnpj_root?: string } }
  | { name: "enrichment_requested" }
  | { name: "enrichment_completed"; props: { status: "done" | "failed" } }
  | { name: "ai_approach_generated"; props: { channel: string; tier: string } }
  | { name: "fit_score_generated" }
  | { name: "whatsapp_click" }
  | { name: "stage_moved"; props: { from: string; to: string } }
  | { name: "activity_added"; props: { type: string } }
  | { name: "lost_reason_given"; props: { reason: string } }
  | { name: "csv_imported"; props: { imported: number } }
  | { name: "sheet_imported"; props: { imported: number } }
  | { name: "leads_exported" }
  | { name: "image_generation_requested"; props: { tier: string } }
  | { name: "image_generation_completed"; props: { status: "ready" | "failed" } }
  | { name: "credits_purchase_intent"; props: { meter: string } }
  | { name: "credits_purchased"; props: { meter: string; quantity: number } }
  | { name: "plan_change_intent"; props: { plan: string } }
  | { name: "consent_accepted"; props: { channel: string } }
  | { name: "channel_connected"; props: { channel: string } }
  | { name: "onboarding_step"; props: { step: number } }
  | { name: "aha_reached" };

declare global {
  interface Window {
    gtag?: (...args: unknown[]) => void;
  }
}

let posthogReady = false;

export function initPostHog(): void {
  const key = publicEnv.NEXT_PUBLIC_POSTHOG_KEY;
  if (!key || posthogReady || typeof window === "undefined") return;
  posthog.init(key, {
    api_host: publicEnv.NEXT_PUBLIC_POSTHOG_HOST,
    capture_pageview: true,
    capture_pageleave: true,
    persistence: "localStorage+cookie",
  });
  posthogReady = true;
}

export function shutdownAnalytics(): void {
  if (posthogReady) posthog.opt_out_capturing();
}

function consented(): boolean {
  return useConsent.getState().analytics === "granted";
}

export function track(event: AnalyticsEvent): void {
  if (!consented()) return;
  const props = "props" in event ? event.props : undefined;
  if (posthogReady) posthog.capture(event.name, props);
  if (typeof window !== "undefined" && window.gtag) {
    window.gtag("event", event.name, props ?? {});
  }
}

export function identifyUser(id: string, traits?: { email?: string; name?: string }): void {
  if (!consented() || !posthogReady) return;
  posthog.identify(id, traits);
}

export function resetIdentity(): void {
  if (posthogReady) posthog.reset();
}

