"use client";

import { apiErrorFromResponse, networkError, ApiError } from "./errors";
import { buildQuery } from "./query";

/**
 * Fetch do client → BFF (/api/backend/*). O browser nunca fala com o Nest
 * nem vê o JWT; o proxy injeta o Bearer server-side.
 */

export interface ClientFetchOptions {
  method?: string;
  body?: unknown;
  query?: Record<string, string | number | boolean | undefined>;
  /** FormData etc. — passa direto */
  rawBody?: BodyInit;
  signal?: AbortSignal;
}

export async function bff<T>(path: string, opts: ClientFetchOptions = {}): Promise<T> {
  const headers: Record<string, string> = {};
  let body: BodyInit | undefined = opts.rawBody;
  if (body === undefined && opts.body !== undefined) {
    headers["Content-Type"] = "application/json";
    body = JSON.stringify(opts.body);
  }

  let res: Response;
  try {
    res = await fetch(`/api/backend${path}${buildQuery(opts.query)}`, {
      method: opts.method ?? "GET",
      headers,
      body,
      signal: opts.signal,
    });
  } catch (e) {
    if (e instanceof DOMException && e.name === "AbortError") throw e;
    throw networkError();
  }

  if (res.status === 401) {
    // sessão caiu — manda pro login preservando a rota
    if (typeof window !== "undefined") {
      const de = encodeURIComponent(window.location.pathname);
      window.location.assign(`/entrar?de=${de}`);
    }
    throw new ApiError(401, "unauthorized", "Sua sessão expirou. Entre de novo pra continuar.");
  }
  if (!res.ok) throw await apiErrorFromResponse(res);
  if (res.status === 204) return undefined as T;

  const contentType = res.headers.get("content-type") ?? "";
  if (!contentType.includes("application/json")) {
    return (await res.blob()) as unknown as T;
  }
  return (await res.json()) as T;
}
